HEADERS = {
    "apikey": KEY,
    "Authorization": f"Bearer {KEY}",
    "Content-Type": "application/json",
    "Accept-Profile": "veilor",
    "Content-Profile": "veilor",
    "Prefer": "return=minimal",
}

def sb_get_all():
    r = requests.get(URL + "?select=id,keyword&limit=1000", headers=HEADERS)
    r.raise_for_status()
    return r.json()

def sb_patch(kw_id, rel_tags, psych_tags):
    r = requests.patch(
        URL + f"?id=eq.{kw_id}",
        headers=HEADERS,
        json={"rel_tags": rel_tags, "psych_tags": psych_tags},
    )
    r.raise_for_status()

def sb_insert_batch(rows):
    r = requests.post(URL, headers=HEADERS, json=rows)
    if r.status_code not in (200, 201):
        print(f"  INSERT ERR {r.status_code}: {r.text[:200]}")
        r.raise_for_status()

