def main():
    print("=== Step 2: 기존 키워드 태그 배정 ===")
    existing = sb_get_all()
    id_map = {row["keyword"]: row["id"] for row in existing}

    patched = 0
    for kw, (rel_tags, psych_tags) in EXISTING_TAGS.items():
        kw_id = id_map.get(kw)
        if kw_id:
            sb_patch(kw_id, rel_tags, psych_tags)
            patched += 1
            print(f"  PATCH: {kw}")
        else:
            print(f"  [WARN] 키워드 없음: {kw}")
    print(f"Step 2 완료: {patched}개 패치\n")

    print("=== Step 3: 신규 키워드 삽입 ===")
    existing_keywords = {row["keyword"] for row in existing}
    to_insert = [k for k in NEW_KEYWORDS if k["keyword"] not in existing_keywords]
    print(f"  삽입 대상: {len(to_insert)}개 (중복 제외)")

    # 배치 단위로 삽입 (Supabase 250개 limit 고려)
    batch_size = 50
    inserted = 0
    for i in range(0, len(to_insert), batch_size):
        batch = to_insert[i:i+batch_size]
        sb_insert_batch(batch)
        inserted += len(batch)
        print(f"  삽입 완료: {inserted}/{len(to_insert)}")
        time.sleep(0.3)

    print(f"\nStep 3 완료: {inserted}개 삽입")

    # 분포 확인
    print("\n=== 카테고리별 분포 확인 ===")
    all_kw = sb_get_all()
    print(f"  총 키워드: {len(all_kw)}개")

if __name__ == "__main__":
    main()
